const websiteMap = {
  1: "Amazon",
  2: "Flipkart",
  3: "Croma"
};

export const transformProduct = (product) => {
  return {
    id: product.id,
    name: product.name,
    stores: product.prices.map(p => ({
      site: websiteMap[p.website] || "Unknown",
      price: parseFloat(p.price),
      link: p.product_url
    }))
  };
};
